import os
import sys
import json
import argparse
import numpy as np
from collections import deque
from cogniplan_env import ExplorationEnv


def round_coords(coords, precision=1):
    return (round(coords[0], precision), round(coords[1], precision))


class ExplorationPlanner:
    def __init__(self, alpha=1.0, alpha_slope=2.0, visited_penalty=0.5,
                 neighbor_util_weight=0.8):
        self.alpha = alpha
        self.alpha_slope = alpha_slope
        self.visited_penalty = visited_penalty
        self.neighbor_util_weight = neighbor_util_weight
        self.visited_positions = set()
        self.step_count = 0

    def reset(self):
        self.visited_positions = set()
        self.step_count = 0

    def select_waypoint(self, obs):
        nodes = obs['nodes']
        neighbors = obs['neighbors']
        robot_pos = obs['robot_pos']
        robot_pos_r = round_coords(robot_pos)
        explored_rate = obs['explored_rate']

        self.visited_positions.add(robot_pos_r)
        self.step_count += 1

        if not neighbors:
            return None

        # Build graph and node lookup
        graph = {}
        node_by_coords = {}
        for node in nodes:
            coords = round_coords(node['coords'])
            node_by_coords[coords] = node
            graph[coords] = [round_coords(n) for n in node['neighbors']]

        # Find start node (closest graph node to robot)
        start = robot_pos_r
        if start not in graph:
            min_dist = float('inf')
            for coords in graph:
                d = (coords[0] - robot_pos_r[0])**2 + (coords[1] - robot_pos_r[1])**2
                if d < min_dist:
                    min_dist = d
                    start = coords

        # BFS from start to compute distances and predecessors
        bfs_distances = {start: 0}
        predecessors = {start: None}
        queue = deque([start])
        while queue:
            current = queue.popleft()
            for nbr in graph.get(current, []):
                if nbr not in bfs_distances:
                    bfs_distances[nbr] = bfs_distances[current] + 1
                    predecessors[nbr] = current
                    queue.append(nbr)

        # Compute aggregated utilities (include neighbor utility)
        agg_utils = {}
        for node in nodes:
            coords = round_coords(node['coords'])
            util = float(node['utility'])
            for nbr_coords in graph.get(coords, []):
                nbr_node = node_by_coords.get(nbr_coords)
                if nbr_node:
                    util += self.neighbor_util_weight * float(nbr_node['utility'])
            agg_utils[coords] = util

        # Adaptive alpha - increases with explored_rate
        eff_alpha = self.alpha + self.alpha_slope * explored_rate

        # Build set of neighbor coords for quick lookup
        neighbor_set = set()
        neighbor_map = {}
        for nbr in neighbors:
            nbr_r = round_coords(nbr)
            neighbor_set.add(nbr_r)
            if nbr_r not in neighbor_map:
                neighbor_map[nbr_r] = nbr

        # Phase 1: Score reachable neighbor nodes WITH visited penalty
        best_target = self._score_neighbors(
            neighbor_set, bfs_distances, agg_utils, eff_alpha, self.visited_penalty)

        # Phase 2: If no attractive neighbor, try WITHOUT visited penalty
        if best_target is None:
            best_target = self._score_neighbors(
                neighbor_set, bfs_distances, agg_utils, eff_alpha, 0.0)

        # Phase 3: Fallback - navigate toward best distant graph node
        if best_target is None:
            best_target = self._fallback_to_distant(
                bfs_distances, agg_utils, eff_alpha, predecessors, start, neighbor_set)

        # Phase 4: Pick any unvisited neighbor
        if best_target is None:
            for nbr_r in neighbor_set:
                if nbr_r not in self.visited_positions:
                    best_target = neighbor_map[nbr_r]
                    break

        # Phase 5: Pick first neighbor
        if best_target is None and neighbors:
            best_target = neighbors[0]

        # Convert from coords back to original format if needed
        if best_target is not None and isinstance(best_target, tuple):
            best_target = neighbor_map.get(best_target, best_target)

        return best_target

    def _score_neighbors(self, neighbor_set, bfs_distances, agg_utils,
                         eff_alpha, visited_penalty):
        best_score = -float('inf')
        best_target = None

        for nbr_r in neighbor_set:
            if nbr_r not in bfs_distances:
                continue

            dist = float(bfs_distances[nbr_r])
            if dist == 0:
                continue

            util = agg_utils.get(nbr_r, 0)

            if nbr_r in self.visited_positions:
                util *= (1.0 - visited_penalty)

            if util <= 0:
                continue

            score = util / (dist ** eff_alpha)
            if score > best_score:
                best_score = score
                best_target = nbr_r

        return best_target

    def _fallback_to_distant(self, bfs_distances, agg_utils, eff_alpha,
                              predecessors, start, neighbor_set):
        """Navigate toward the best distant node with highest utility/distance ratio."""
        best_score = -float('inf')
        best_node = None

        for coords, util in agg_utils.items():
            if util <= 0:
                continue
            if coords not in bfs_distances:
                continue
            dist = float(bfs_distances[coords])
            if dist <= 1:
                continue  # Skip immediate neighbors (already tried)
            score = util / (dist ** eff_alpha)
            if score > best_score:
                best_score = score
                best_node = coords

        if best_node is None:
            return None

        # Trace path back from best_node to start, find first step
        path = []
        current = best_node
        while current is not None and current != start:
            path.append(current)
            current = predecessors.get(current)
            if current is None or len(path) > 200:
                break

        # Find the first node on the path that is a neighbor
        path.reverse()
        for node in path:
            if node in neighbor_set:
                return node

        return None


def run_episode(env, planner):
    obs = env.reset()
    planner.reset()
    for step in range(128):
        target = planner.select_waypoint(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get('done', False):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, required=True)
    parser.add_argument('--output', type=str, required=True)
    args = parser.parse_args()

    # Load config if available
    config_path = os.path.join(args.checkpoint, 'config.json')
    if os.path.exists(config_path):
        with open(config_path, 'r') as f:
            config = json.load(f)
    else:
        config = {}

    alpha = config.get('alpha', 1.0)
    alpha_slope = config.get('alpha_slope', 2.0)
    visited_penalty = config.get('visited_penalty', 0.5)
    neighbor_util_weight = config.get('neighbor_util_weight', 0.8)

    # Load eval config
    eval_config_path = os.path.join(args.data_path, 'eval_config.json')
    if os.path.exists(eval_config_path):
        with open(eval_config_path, 'r') as f:
            eval_config = json.load(f)
    else:
        eval_config = {}

    env_types = eval_config.get('env_types', ['room', 'tunnel', 'outdoor'])

    # Find all eval maps
    eval_maps = []
    maps_dir = os.path.join(args.data_path, 'maps_eval')
    if not os.path.exists(maps_dir):
        maps_dir = os.path.join(args.data_path, 'maps_train')

    for env_type in env_types:
        type_dir = os.path.join(maps_dir, env_type)
        if os.path.exists(type_dir):
            for fname in sorted(os.listdir(type_dir)):
                if fname.endswith('.png'):
                    map_path = os.path.join(type_dir, fname)
                    rel_path = os.path.join(env_type, fname)
                    eval_maps.append((map_path, env_type, rel_path))

    # Run evaluation
    planner = ExplorationPlanner(
        alpha=alpha,
        alpha_slope=alpha_slope,
        visited_penalty=visited_penalty,
        neighbor_util_weight=neighbor_util_weight,
    )

    per_episode = []
    total_explored = 0
    total_success = 0
    succ_distances = []
    per_type_data = {et: {'explored': [], 'dist': [], 'success': []} for et in env_types}

    for map_path, env_type, rel_path in eval_maps:
        env = ExplorationEnv(map_path=map_path)
        metrics = run_episode(env, planner)

        success = 1 if metrics['success'] else 0
        explored = metrics['explored_rate']
        dist = metrics['travel_distance']

        per_episode.append({
            'map_path': rel_path,
            'env_type': env_type,
            'success': success,
            'travel_distance': dist,
            'explored_rate': explored,
        })

        total_explored += explored
        total_success += success
        if success:
            succ_distances.append(dist)

        per_type_data[env_type]['explored'].append(explored)
        per_type_data[env_type]['dist'].append(dist)
        per_type_data[env_type]['success'].append(success)

    n = len(eval_maps)
    result = {
        'explored_rate': total_explored / n if n > 0 else 0,
        'travel_distance': np.mean(succ_distances) if succ_distances else 0.0,
        'success_rate': total_success / n if n > 0 else 0,
        'per_episode': per_episode,
        'per_type': {},
        'total_episodes': n,
    }

    for et in env_types:
        td = per_type_data[et]
        n_type = len(td['success'])
        if n_type > 0:
            succ_d = [d for d, s in zip(td['dist'], td['success']) if s == 1]
            result['per_type'][et] = {
                'explored_rate': np.mean(td['explored']),
                'travel_distance': np.mean(succ_d) if succ_d else 0.0,
                'success_rate': np.mean(td['success']),
            }

    with open(args.output, 'w') as f:
        json.dump(result, f, indent=2)

    print(f'Done: {n} episodes, success={result["success_rate"]:.3f}, '
          f'dist={result["travel_distance"]:.1f}, explored={result["explored_rate"]:.4f}')


if __name__ == '__main__':
    main()
